// ═══════════════════════════════════════════════════════════════════════════
// КОНСТАНТЫ
// ═══════════════════════════════════════════════════════════════════════════

// Карта режимов VAKIO: строка → номер ActiveIdentifier
var WORKMODE_MAP = {
  inflow: 1, inflow_max: 2, recuperator: 3,
  winter: 4, outflow: 5, outflow_max: 6, night: 7
};

// Возвращает список режимов для formType list
function WORKMODE_VALUES() {
  return [
    { name: { ru: "Приток",          en: "Inflow"           }, value: "inflow"      },
    { name: { ru: "Приток MAX",      en: "Inflow MAX"       }, value: "inflow_max"  },
