    { name: { ru: "Рекуперация зима",en: "Recuperator winter"}, value: "winter"     },
    { name: { ru: "Вытяжка",         en: "Outflow"          }, value: "outflow"     },
    { name: { ru: "Вытяжка MAX",     en: "Outflow MAX"      }, value: "outflow_max" },
    { name: { ru: "Ночной",          en: "Night"            }, value: "night"       }
  ];
}

// ═══════════════════════════════════════════════════════════════════════════
// ТОЧКА ВХОДА
// Вызывается при изменении HC.Active рекуператора и при onStart
// ═══════════════════════════════════════════════════════════════════════════
function trigger(source, value, variables, options, context) {
  try {
    setupCron(variables, options, source);
    runLogic(variables, options);
  } catch (e) {
    console.error("[Рекуператор] trigger: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ПЕРИОДИЧЕСКАЯ ПРОВЕРКА
// Запускает runLogic каждую минуту — логика работает даже без событий
// ═══════════════════════════════════════════════════════════════════════════
function setupCron(variables, options, source) {
  var sameSettings = (variables.prevNightStart === options.nightStart &&
                      variables.prevNightEnd   === options.nightEnd);
  if (sameSettings && variables.checkCron) return;

  if (variables.checkCron) { variables.checkCron.clear(); variables.checkCron = undefined; }

  variables.prevNightStart = options.nightStart;
  variables.prevNightEnd   = options.nightEnd;

  variables.checkCron = Cron.schedule("0 * * * * *", function() {
    try { runLogic(variables, options); }
    catch(e) { console.error("[Рекуператор] cron: " + e.message); }
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// ОСНОВНАЯ ЛОГИКА
// Определяет режим и направляет в нужный обработчик
// ═══════════════════════════════════════════════════════════════════════════
function runLogic(variables, options) {
  var secState = getSecurityState(options.securityService);

  // Режим «Не дома» — логика полностью неактивна
  if (secState === 1) { return; }

  var isNight = (secState === 2) || isNightTime(options);
  var role    = options.role || "bedroom";

  logDebug("Проверка: режим=" + secState + " ночь=" + isNight + " роль=" + roleRu(role), options, variables);

  // Если окно открыто — выключаем рекуператор и не управляем им
  if (checkWindowOpen(options, role, variables)) {
    applyToSelf(options, false, 0, "", variables, false);
    resetDynamic(variables);
    return;
  }

  if (isNight) {
    handleNight(variables, options, role);
  } else {
    handleDay(variables, options, role);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// НОЧНОЙ РЕЖИМ
// Спальня: приток по CO₂. Гостиная: вытяжка с той же скоростью.
// Если CO₂ гостиной > co2Spd5 — гостиная переходит в приток + вытяжки
// ═══════════════════════════════════════════════════════════════════════════
function handleNight(variables, options, role) {
  if (role === "bedroom") {
    var co2  = readSensor(options.co2BedroomService,  HC.CarbonDioxideLevel);
    var voc  = readSensor(options.vocBedroomService,  HC.VOCDensity);
    var pm25 = readSensor(options.pm25BedroomService, HC.PM2_5Density);
    var pm10 = readSensor(options.pm10BedroomService, HC.PM10Density);

    var spdCO2  = (co2  !== null) ? valueToSpeed(co2,  options, "co2")  : 0;
    var spdVOC  = (voc  !== null) ? valueToSpeed(voc,  options, "voc")  : 0;
    var spdPM25 = (pm25 !== null) ? valueToSpeed(pm25, options, "pm25") : 0;
    var spdPM10 = (pm10 !== null) ? valueToSpeed(pm10, options, "pm10") : 0;

    var pollutantSpd = Math.max(spdVOC, spdPM25, spdPM10);
    var co2Spd       = spdCO2;

    // Все показатели в норме — выключаем
    if (pollutantSpd === 0 && co2Spd === 0) {
      applyToSelf(options, false, 0, "", variables, false);
      setAuxFans(options, false, variables);
      resetDynamic(variables);
      return;
    }

    var finalSpd, workmode;

    if (pollutantSpd >= co2Spd && pollutantSpd > 0) {
      // VOC/PM — вытяжка (даже ночью выводим загрязнители)
      var worstType = "voc";
      var worstSpd  = spdVOC;
      var worstVal  = voc  || 0;
      if (spdPM25 > worstSpd) { worstSpd = spdPM25; worstVal = pm25 || 0; worstType = "pm25"; }
      if (spdPM10 > worstSpd) { worstSpd = spdPM10; worstVal = pm10 || 0; worstType = "pm10"; }

      finalSpd = applyDynamic(pollutantSpd, worstVal, worstType, variables, options);
      finalSpd = Math.max(finalSpd, clamp(options.nightSpeedBedroom));
      workmode = options.dayModeBedroomVOC;

      if (options.enableAuxFans && finalSpd >= (options.auxFanMinSpeed || 6)) {
        setAuxFans(options, true, variables);
      }
    } else {
      // CO₂ — приток
      finalSpd = applyDynamic(co2Spd, co2, "co2_bed", variables, options);
      finalSpd = Math.max(finalSpd, clamp(options.nightSpeedBedroom));
      workmode = options.nightModeBedroom;
      setAuxFans(options, false, variables);
    }

    applyToSelf(options, true, finalSpd, workmode, variables, pollutantSpd >= co2Spd && pollutantSpd > 0);

  } else {
    // Гостиная ночью
    // Если включена синхронизация — берём скорость из партнёра (спальня)
    if (options.syncSpeedWithBedroom) {
      var partnerSvc = getService(options.partnerFanService);
      if (partnerSvc) {
        var partnerActive = partnerSvc.getCharacteristic(HC.Active).getValue();
        if (partnerActive === 1) {
          // Спальня работает — берём её скорость, режим гостиной = вытяжка
          var partnerSpeed = Math.round(partnerSvc.getCharacteristic(HC.RotationSpeed).getValue()) || 1;
          applyToSelf(options, true, partnerSpeed, options.nightModeLiving, variables, false);
          logDebug("[Гостиная] Ночь: синхронизация со спальней скорость=" + partnerSpeed, options, variables);
          return;
        } else {
          // Спальня выключена — fallback на собственные датчики гостиной
          logDebug("[Гостиная] Ночь: спальня выкл → работаем по своим датчикам", options, variables);
          // Продолжаем выполнение — не делаем return
        }
      }
    }

    var co2Liv   = readSensor(options.co2LivingService, HC.CarbonDioxideLevel);
    var calcSpd  = (co2Liv !== null) ? valueToSpeed(co2Liv, options, "co2") : 0;

    // Включаем только если CO₂ выше нормы
    if (calcSpd === 0) {
      applyToSelf(options, false, 0, "", variables, false);
      resetDynamic(variables);
      return;
    }

    // nightSpeedLiving — минимальная скорость когда рекуператор уже включён
    var speed = Math.max(calcSpd, clamp(options.nightSpeedLiving));

    // Если CO₂ критически высокий — приток вместо вытяжки
    var workmode = options.nightModeLiving;
    if (co2Liv !== null && co2Liv > options.co2Spd5) {
      workmode = options.dayModeLivingCO2;
      if (options.enableAuxFans && speed >= (options.auxFanMinSpeed || 3)) { setAuxFans(options, true, variables); }
      console.info("[Рекуператор Б] Ночь/гостиная: CO₂ критический (" + co2Liv + ") → приток + вытяжки");
    }

    applyToSelf(options, true, speed, workmode, variables, false);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ДНЕВНОЙ РЕЖИМ
// Спальня: CO₂. Гостиная: VOC/PM (вытяжка) приоритет над CO₂ (приток)
// ═══════════════════════════════════════════════════════════════════════════
function handleDay(variables, options, role) {
  if (role === "bedroom") {

      var co2  = readSensor(options.co2BedroomService, HC.CarbonDioxideLevel);

      var voc  = readSensor(options.vocBedroomService,  HC.VOCDensity);
      var pm25 = readSensor(options.pm25BedroomService, HC.PM2_5Density);
      var pm10 = readSensor(options.pm10BedroomService, HC.PM10Density);

      var spdCO2  = (co2  !== null) ? valueToSpeed(co2, options, "co2")  : 0;
      var spdVOC  = (voc  !== null) ? valueToSpeed(voc, options, "voc")  : 0;
      var spdPM25 = (pm25 !== null) ? valueToSpeed(pm25, options, "pm25") : 0;
      var spdPM10 = (pm10 !== null) ? valueToSpeed(pm10, options, "pm10") : 0;

      var pollutantSpd = Math.max(spdVOC, spdPM25, spdPM10);
      var co2Spd = spdCO2;

      if (pollutantSpd === 0 && co2Spd === 0) {
          applyToSelf(options, false, 0, "", variables, false);
          setAuxFans(options, false, variables);
          resetDynamic(variables);
          return;
      }

      var finalSpd;
      var workmode;

      if (pollutantSpd >= co2Spd) {

          var worstType = "voc";
          var worstSpd  = spdVOC;
          var worstVal  = voc || 0;

          if (spdPM25 > worstSpd) {
              worstSpd  = spdPM25;
              worstVal  = pm25 || 0;
              worstType = "pm25";
          }

          if (spdPM10 > worstSpd) {
              worstSpd  = spdPM10;
              worstVal  = pm10 || 0;
              worstType = "pm10";
          }

          finalSpd = applyDynamic(
              pollutantSpd,
              worstVal,
              worstType,
              variables,
              options
          );

          workmode = options.dayModeBedroomVOC;

          if (
              options.enableAuxFans &&
              finalSpd >= (options.auxFanMinSpeed || 3)
          ) {
              setAuxFans(options, true, variables);
          }

      } else {

          finalSpd = applyDynamic(
              co2Spd,
              co2,
              "co2_bed",
              variables,
              options
          );

          workmode = options.dayModeBedroom;

          setAuxFans(options, false, variables);
      }

      applyToSelf(
          options,
          true,
          finalSpd,
          workmode,
          variables,
          pollutantSpd >= co2Spd && pollutantSpd > 0
      );

      return;
  }

  // ── Гостиная: читаем все датчики ──────────────────────────────────────
  var co2  = readSensor(options.co2LivingService,  HC.CarbonDioxideLevel);
  var voc  = readSensor(options.vocLivingService,  HC.VOCDensity);
  var pm25 = readSensor(options.pm25LivingService, HC.PM2_5Density);
  var pm10 = readSensor(options.pm10LivingService, HC.PM10Density);
  var vocK = readSensor(options.vocKitchenService, HC.VOCDensity);

  var spdCO2  = (co2  !== null) ? valueToSpeed(co2,  options, "co2")        : 0;
  var spdVOC  = (voc  !== null) ? valueToSpeed(voc,  options, "voc")        : 0;
  var spdPM25 = (pm25 !== null) ? valueToSpeed(pm25, options, "pm25")       : 0;
  var spdPM10 = (pm10 !== null) ? valueToSpeed(pm10, options, "pm10")       : 0;
  var spdVocK = (vocK !== null) ? valueToSpeed(vocK, options, "vocKitchen") : 0;

  // Загрязнители (вытяжка) vs CO₂ (приток)
  var pollutantSpd = Math.max(spdVOC, spdPM25, spdPM10, spdVocK);
  var co2Spd       = spdCO2;

  if (pollutantSpd === 0 && co2Spd === 0) {
    applyToSelf(options, false, 0, "", variables, false);
    setAuxFans(options, false, variables);
    resetDynamic(variables);
    return;
  }

  var finalSpd, workmode, reason;

  if (pollutantSpd >= co2Spd) {
    // Загрязнители важнее — вытяжка
    // Определяем какой показатель даёт максимальную скорость — по нему гистерезис
    var worstType = "voc";
    var worstSpd  = spdVOC;
    var worstVal  = voc  || 0;
    if (spdVocK > worstSpd) { worstSpd = spdVocK; worstVal = vocK  || 0; worstType = "vocKitchen"; }
    if (spdPM25 > worstSpd) { worstSpd = spdPM25; worstVal = pm25  || 0; worstType = "pm25"; }
    if (spdPM10 > worstSpd) { worstSpd = spdPM10; worstVal = pm10  || 0; worstType = "pm10"; }
    finalSpd = applyDynamic(pollutantSpd, worstVal, worstType, variables, options);
    workmode = options.dayModeLivingVOC;
    reason   = "VOC=" + voc + " PM25=" + pm25 + " PM10=" + pm10 + " VOCkit=" + vocK + " (тип=" + worstType + ")";
    if (options.enableAuxFans && finalSpd >= (options.auxFanMinSpeed || 3)) setAuxFans(options, true, variables);
  } else {
    // CO₂ — приток
    finalSpd = applyDynamic(co2Spd, co2, "co2_liv", variables, options);
    workmode = options.dayModeLivingCO2;
    reason   = "CO₂=" + co2;
    setAuxFans(options, false, variables);
  }

  applyToSelf(options, true, finalSpd, workmode, variables, pollutantSpd >= co2Spd && pollutantSpd > 0);
}

// ═══════════════════════════════════════════════════════════════════════════
// ПРИМЕНИТЬ НАСТРОЙКИ К РЕКУПЕРАТОРУ + ЛОГИРОВАТЬ ТОЛЬКО ИЗМЕНЕНИЯ
// ═══════════════════════════════════════════════════════════════════════════
function applyToSelf(options, active, speed, workmode, variables, auxFans) {
  var svc = getService(options.selfFanService);
  if (!svc) { logWarn("[" + roleRu(options.role) + "] selfFanService не задан"); return; }

  // Логируем только если что-то изменилось
  var last = variables ? variables.lastState : undefined;
  var changed = !last ||
    last.active   !== active   ||
    last.speed    !== speed    ||
    last.workmode !== workmode ||
    last.auxFans  !== auxFans;

  if (changed) {
    var label = active
      ? ("вкл → " + workmodeRu(workmode) + " скорость=" + speed + (auxFans ? " + вытяжки ВКЛ" : ""))
      : "выкл";
    var prev = last
      ? ("было: " + (last.active ? workmodeRu(last.workmode) + " скорость=" + last.speed : "выкл"))
      : "первый запуск";
    logInfo("[" + roleRu(options.role) + "] Изменение: " + label + " | " + prev, options);
    if (variables) variables.lastState = { active: active, speed: speed, workmode: workmode, auxFans: !!auxFans };
  }

  setFanService(svc, active, speed, workmode);
}

// ═══════════════════════════════════════════════════════════════════════════
// УПРАВЛЕНИЕ FAN-СЕРВИСОМ РЕКУПЕРАТОРА
// Устанавливает Active, RotationSpeed и режим работы (ActiveIdentifier)
// ═══════════════════════════════════════════════════════════════════════════
function setFanService(fanSvc, active, speed, workmode) {
  try {
    fanSvc.getCharacteristic(HC.Active).setValue(active ? 1 : 0);
    if (active && speed > 0) {
      fanSvc.getCharacteristic(HC.RotationSpeed).setValue(clamp(speed));
    }
    // Переключаем режим (workmode) через Television-сервис того же аксессуара
    if (active && workmode) {
      var acc   = fanSvc.getAccessory();
      var tvSvc = null;
      acc.getServices().forEach(function(svc) {
        if (svc.getType() === HS.Television) { tvSvc = svc; }
      });
      if (tvSvc) {
        var modeId = WORKMODE_MAP[workmode] || 1;
        tvSvc.getCharacteristic(HC.ActiveIdentifier).setValue(modeId);
      }
    }
  } catch(e) {
    console.error("[Рекуператор] setFanService: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// УПРАВЛЕНИЕ ВСПОМОГАТЕЛЬНЫМИ ВЫТЯЖКАМИ
// Включаем когда нужно. Выключаем ТОЛЬКО если мы их включили —
// не трогаем вентиляторы запущенные другими сценариями (влажность, ДП).
// ═══════════════════════════════════════════════════════════════════════════
function setAuxFans(options, on, variables) {
  if (on) {
    if (!variables.auxFansOn) {
      setFanBasic(options.fanToiletService,    true);
      setFanBasic(options.fanBathroom1Service, true);
      setFanBasic(options.fanBathroom2Service, true);
      variables.auxFansOn = true;
      logInfo("Вытяжки ванной/туалета включены (VOC/PM)", options);
    }
  } else {
    if (variables.auxFansOn) {
      setFanBasic(options.fanToiletService,    false);
      setFanBasic(options.fanBathroom1Service, false);
      setFanBasic(options.fanBathroom2Service, false);
      variables.auxFansOn = false;
      logInfo("Вытяжки ванной/туалета выключены", options);
    }
  }
}

// Управляет одним FanBasic (HC.On)
function setFanBasic(serviceUUID, on) {
  if (!serviceUUID || serviceUUID === "") return;
  try {
    var svc = getService(serviceUUID);
    if (svc) svc.getCharacteristic(HC.On).setValue(on ? true : false);
  } catch(e) {
    console.error("[Рекуператор] setFanBasic: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ДИНАМИКА СКОРОСТИ С ГИСТЕРЕЗИСОМ
//
// КЛЮЧЕВОЕ ИСПРАВЛЕНИЕ v4.3:
// boostedSpeed хранится в variables и НЕ перезаписывается baseSpeed при
// каждом вызове. Это решает проблему зависания: когда рекуператор уже
// работает на повышенной скорости, baseSpeed (по датчику) меньше boostedSpeed,
// но мы продолжаем работать на boostedSpeed пока не выполнится условие
// понижения по гистерезису.
//
// Повышение: если sensorValue не улучшается t10 мин → boostedSpeed +1
//            если после первого буста ещё t30 мин → ещё +1
// Понижение: только если sensorValue < нижней границы boostedSpeed
// Выключение: baseSpeed = 0 (датчик в норме) — сбрасываем, возвращаем 0
//
// variables.lastDecision: { type, boostedSpeed, value, ts, boost2ts }
// ═══════════════════════════════════════════════════════════════════════════
function applyDynamic(baseSpeed, sensorValue, type, variables, options) {
  // Датчик говорит выключить — сбрасываем всю динамику
  if (baseSpeed === 0) {
    resetDynamic(variables);
    return 0;
  }

  var now  = Date.now();
  var t10  = (options.dynamicMinutes || 10) * 60 * 1000;
  var t30  = 30 * 60 * 1000;
  var last = variables.lastDecision;
  var role = options.role || "bedroom";

  // Первый вызов или смена типа показателя — инициализируем
  if (!last || last.type !== type) {
    variables.lastDecision = {
      type: type, boostedSpeed: baseSpeed,
      value: sensorValue, ts: now, boost2ts: null
    };
    logDebug("[" + roleRu(role) + "] Динамика инициализирована: тип=" + type +
      " значение=" + sensorValue + " скорость=" + baseSpeed, options, variables);
    return baseSpeed;
  }

  var boosted    = last.boostedSpeed;
  var lowerBound = getLowerBound(boosted, options, type);

  // ── Понижение по гистерезису ─────────────────────────────────────────────
  // Снижаем только если sensorValue упал НИЖЕ нижней границы текущей скорости
  if (sensorValue < lowerBound) {
    var newSpeed = baseSpeed;
    if (newSpeed < boosted) {
      logInfo("[" + roleRu(role) + "] Снижение скорости [" + type + "]: " +
        sensorValue + " < " + lowerBound +
        " (нижняя граница скорости " + boosted + ") → скорость " + boosted + "→" + newSpeed, options);
      variables.lastDecision = {
        type: type, boostedSpeed: newSpeed,
        value: sensorValue, ts: now, boost2ts: null
      };
      return newSpeed;
    }
  }

  // ── Повышение +1: через t10 минут без улучшения ───────────────────────────
  // Сравниваем с последним зафиксированным значением, не с baseSpeed
  if (sensorValue >= last.value && (now - last.ts) >= t10 && boosted < 7) {
    var b1 = clamp(boosted + 1);
    logInfo("[" + roleRu(role) + "] Динамика +1 [" + type + "]: " +
      sensorValue + " не улучшился за " + (options.dynamicMinutes || 10) +
      " мин → скорость " + boosted + "→" + b1, options);
    variables.lastDecision = {
      type: type, boostedSpeed: b1,
      value: sensorValue, ts: now,
      boost2ts: last.boost2ts || now  // фиксируем момент первого буста
    };
    return b1;
  }

  // ── Повышение +1: через t30 минут после первого буста ────────────────────
  if (last.boost2ts && sensorValue >= last.value && (now - last.boost2ts) >= t30 && boosted < 7) {
    var b2 = clamp(boosted + 1);
    logInfo("[" + roleRu(role) + "] Динамика +1 (30 мин) [" + type + "]: " +
      sensorValue + " не улучшился за 30 мин → скорость " + boosted + "→" + b2, options);
    variables.lastDecision = {
      type: type, boostedSpeed: b2,
      value: sensorValue, ts: now,
      boost2ts: null  // сбрасываем — следующий буст отсчитывается заново
    };
    return b2;
  }

  // Если значение улучшилось — обновляем базу сравнения
  if (sensorValue < last.value) {
    variables.lastDecision.value = sensorValue;
    logDebug("[" + roleRu(role) + "] Динамика: значение улучшилось " +
      last.value + "→" + sensorValue + " (скорость остаётся " + boosted + ")", options, variables);
  }

  // Возвращаем boostedSpeed — НЕ baseSpeed
  // Это ключевое: даже если baseSpeed упал (но выше lowerBound),
  // продолжаем работать на повышенной скорости
  return boosted;
}

// Нижняя граница текущей скорости — значение ниже которого скорость снижается
// Для co2: нижняя граница скорости N = верхняя граница скорости (N-1)
// Для скорости 1 — нижняя граница = off-порог
function getLowerBound(speed, options, type) {
  var off, s1, s2, s3, s4, s5;
  if (type === "co2" || type === "co2_bed" || type === "co2_liv") {
    off=options.co2Off; s1=options.co2Spd1; s2=options.co2Spd2;
    s3=options.co2Spd3; s4=options.co2Spd4; s5=options.co2Spd5;
  } else if (type === "voc") {
    off=options.vocOff; s1=options.vocSpd1; s2=options.vocSpd2;
    s3=options.vocSpd3; s4=options.vocSpd4; s5=options.vocSpd5;
  } else if (type === "vocKitchen") {
    off=options.vocKitOff; s1=options.vocKitSpd1; s2=options.vocKitSpd2;
    s3=options.vocKitSpd3; s4=options.vocKitSpd4; s5=options.vocKitSpd5;
  } else if (type === "pm25") {
    off=options.pm25Off; s1=options.pm25Spd1; s2=options.pm25Spd2;
    s3=options.pm25Spd3; s4=options.pm25Spd4; s5=options.pm25Spd5;
  } else {
    off=options.pm10Off; s1=options.pm10Spd1; s2=options.pm10Spd2;
    s3=options.pm10Spd3; s4=options.pm10Spd4; s5=options.pm10Spd5;
  }
  var bounds = [off, off, s1, s2, s3, s4, s5];
  return bounds[speed] !== undefined ? bounds[speed] : off;
}

function resetDynamic(variables) { variables.lastDecision = undefined; }

// ═══════════════════════════════════════════════════════════════════════════
// ПЕРЕВОД ЗНАЧЕНИЯ ДАТЧИКА → СКОРОСТЬ 0-7
// type: 'co2' | 'voc' | 'vocKitchen' | 'pm25' | 'pm10'
// ═══════════════════════════════════════════════════════════════════════════
function valueToSpeed(val, options, type) {
  var off, s1, s2, s3, s4, s5, s6;
  if (type === "co2") {
    off=options.co2Off;  s1=options.co2Spd1; s2=options.co2Spd2; s3=options.co2Spd3;
    s4=options.co2Spd4;  s5=options.co2Spd5; s6=options.co2Spd6;
  } else if (type === "voc") {
    off=options.vocOff;  s1=options.vocSpd1; s2=options.vocSpd2; s3=options.vocSpd3;
    s4=options.vocSpd4;  s5=options.vocSpd5; s6=options.vocSpd6;
  } else if (type === "vocKitchen") {
    off=options.vocKitOff;  s1=options.vocKitSpd1; s2=options.vocKitSpd2; s3=options.vocKitSpd3;
    s4=options.vocKitSpd4;  s5=options.vocKitSpd5; s6=options.vocKitSpd6;
  } else if (type === "pm25") {
    off=options.pm25Off; s1=options.pm25Spd1; s2=options.pm25Spd2; s3=options.pm25Spd3;
    s4=options.pm25Spd4; s5=options.pm25Spd5; s6=options.pm25Spd6;
  } else {
    off=options.pm10Off; s1=options.pm10Spd1; s2=options.pm10Spd2; s3=options.pm10Spd3;
    s4=options.pm10Spd4; s5=options.pm10Spd5; s6=options.pm10Spd6;
  }
  if (!val || val <= off) return 0;
  if (val <= s1) return 1;
  if (val <= s2) return 2;
  if (val <= s3) return 3;
  if (val <= s4) return 4;
  if (val <= s5) return 5;
  if (val <= s6) return 6;
  return 7;
}

// ═══════════════════════════════════════════════════════════════════════════
// ЧТЕНИЕ ДАТЧИКА С ПРОВЕРКОЙ ДОСТУПНОСТИ
// Возвращает числовое значение или null если датчик недоступен/не задан
// ═══════════════════════════════════════════════════════════════════════════
function readSensor(serviceUUID, charType) {
  if (!serviceUUID || serviceUUID === "") return null;
  try {
    var svc = getService(serviceUUID);
    if (!svc) return null;

    // Проверяем доступность через HC.C_Online
    var acc     = svc.getAccessory();
    var infoSvc = null;
    acc.getServices().forEach(function(s) {
      if (s.getType() === HS.AccessoryInformation) { infoSvc = s; }
    });
    if (infoSvc) {
      var online = infoSvc.getCharacteristic(HC.C_Online);
      if (online && online.getValue() !== true) {
        logWarn("Датчик недоступен (offline): " + serviceUUID);
        return null;
      }
    }

    var val = svc.getCharacteristic(charType);
    return (val !== null && val !== undefined) ? val.getValue() : null;
  } catch(e) {
    logWarn("readSensor(" + serviceUUID + "): " + e.message);
    return null;
  }
}

// Логирование: всегда пишем важные события, debug — только если включён режим
function logInfo(msg, options) {
