// ═══════════════════════════════════════════════════════════════════════════
// ПРОВЕРКА ОТКРЫТЫХ ОКОН
// Проверяет все 4 датчика (windowSensor1-4), логирует только при изменении.
// ContactSensorState: 0 = закрыто, 1 = открыто
// ═══════════════════════════════════════════════════════════════════════════
function checkWindowOpen(options, role, variables) {
  var sensors = [
    options.windowSensor1, options.windowSensor2,
    options.windowSensor3, options.windowSensor4
  ].filter(function(s) { return s && s !== ""; });

  if (sensors.length === 0) return false;

  var openSensor = null;
  for (var i = 0; i < sensors.length; i++) {
    try {
      var svc = getService(sensors[i]);
      if (!svc) continue;
      var val = svc.getCharacteristic(HC.ContactSensorState).getValue();
      if (val === 1) { openSensor = sensors[i]; break; }
    } catch(e) { /* игнорируем недоступные датчики */ }
  }

  var isOpen = (openSensor !== null);

  // Логируем только при изменении состояния
  var lastOpen = variables ? variables.lastWindowOpen : undefined;
  if (lastOpen !== isOpen) {
    if (isOpen) {
      logInfo("[" + roleRu(role) + "] Окно открыто — рекуператор выключается", options);
    } else {
      logInfo("[" + roleRu(role) + "] Окно закрыто — рекуператор возобновляет работу", options);
    }
    if (variables) variables.lastWindowOpen = isOpen;
  }

  return isOpen;
}

