// ═══════════════════════════════════════════════════════════════════════════
// ПОЛУЧИТЬ СЕРВИС ПО UUID "accId.svcId"
// ═══════════════════════════════════════════════════════════════════════════
function getService(uuid) {
  if (!uuid || uuid === "") return null;
  try {
    var parts = uuid.split(".");
    var accId = parts[0];
    var svcId = parts[1];
    return Hub.getAccessory(accId).getService(svcId);
  } catch(e) {
    logWarn("getService(" + uuid + "): " + e.message);
    return null;
  }
}

// Читает текущий режим охраны
function getSecurityState(serviceUUID) {
  try {
    var svc = getService(serviceUUID);
    if (!svc) return 0;
    return svc.getCharacteristic(HC.SecuritySystemCurrentState).getValue();
  } catch(e) {
    logWarn("getSecurityState: " + e.message);
    return 0;
  }
}

// Определяет ночное время по строкам ЧЧ:ММ
function isNightTime(options) {
  var now   = new Date();
  var cur   = now.getHours() * 60 + now.getMinutes();
  var tS    = parseTime(options.nightStart);
  var tE    = parseTime(options.nightEnd);
  var start = tS.h * 60 + tS.m;
  var end   = tE.h * 60 + tE.m;
  return (start > end) ? (cur >= start || cur < end) : (cur >= start && cur < end);
}

// Парсит «ЧЧ:ММ» → { h, m }
function parseTime(str) {
  var parts = (str || "00:00").match(/^(\d{1,2}):(\d{2})$/);
  if (!parts) return { h: 0, m: 0 };
  return { h: parseInt(parts[1], 10), m: parseInt(parts[2], 10) };
}

// Ограничивает скорость диапазоном 1-7
function clamp(v) {
  var n = parseInt(v, 10) || 1;
  return n < 1 ? 1 : n > 7 ? 7 : n;
}

// ═══════════════════════════════════════════════════════════════════════════
// ПОДГОТОВКА СПИСКА СЕРВИСОВ ДЛЯ OPTIONS (formType list)
// ═══════════════════════════════════════════════════════════════════════════
function getServiceList(serviceTypes, charType) {
  var result = [{ name: { ru: "Не выбрано", en: "Not selected" }, value: "" }];
  var unsorted = [];
  Hub.getAccessories().forEach(function(acc) {
    acc.getServices().filter(function(svc) {
      return serviceTypes.indexOf(svc.getType()) >= 0;
    }).forEach(function(svc) {
      var c = svc.getCharacteristic(charType);
      if (c) {
        var accName  = acc.getName();
        var svcName  = svc.getName();
        var roomName = acc.getRoom() ? acc.getRoom().getName() : "";
        var label    = roomName + " → " + (accName === svcName ? accName : accName + " " + svcName) + " (" + svc.getUUID() + ")";
        unsorted.push({ name: { ru: label, en: label }, value: svc.getUUID() });
      }
    });
  });
  unsorted.sort(function(a, b) { return a.name.ru.localeCompare(b.name.ru); });
  unsorted.forEach(function(s) { result.push(s); });
  return result;
}
